func TestEnumMethodall(t *testing.T) {
	t.Run("NewFromString_card", func(t *testing.T) {
		t.Parallel()
		val, err := NewMethodallFromString("card")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Methodall("card"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_ach", func(t *testing.T) {
		t.Parallel()
		val, err := NewMethodallFromString("ach")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Methodall("ach"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_cloud", func(t *testing.T) {
		t.Parallel()
		val, err := NewMethodallFromString("cloud")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Methodall("cloud"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_check", func(t *testing.T) {
		t.Parallel()
		val, err := NewMethodallFromString("check")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Methodall("check"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_cash", func(t *testing.T) {
		t.Parallel()
		val, err := NewMethodallFromString("cash")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Methodall("cash"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewMethodallFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewMethodallFromString("card")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

